var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"아직 멀었나? 미안하지만 이터니움 실드가 거의 바닥이야.","JPN":"まだなのか？　悪いがエタニウムシールドがそろそろ限界だ。","ENG":"Are we close? Sorry, but the Eternium shield's nearly drained.","TWN":"還有多遠？不好意思，但我的永恆之金護盾快用完了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"얼마 안 남았네.","JPN":"あと少しだ。","ENG":"Not far now.","TWN":"快到了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이쪽으로 더 가면 곧… 음?","JPN":"こちらへ進めば……うん？","ENG":"Just a little farther and– Hmm?","TWN":"再往這邊走，很快就…嗯？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_14","text":{"KOREA":"뭐해? 왜 갑자기 멈추는 건가!","JPN":"どうした？　なぜ急に止まる！","ENG":"What are you doing? Why'd you stop all of a sudden?!","TWN":"在幹嘛？為什麼突然停下來！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이곳은 꿈도 아니고, 과거도 아닌데…","JPN":"ここは夢でも過去でもないというのに……","ENG":"This isn't a dream or the past…","TWN":"這裡不是夢，也不是過去…"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 어째서 여기에…?","JPN":"なぜそなたがここに……？","ENG":"Then why are you here…?","TWN":"你為什麼會在這裡…？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"잠깐만. 멈추게.","JPN":"少し待っていてくれ。","ENG":"Wait. Hold on.","TWN":"等一下。停下來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"이봐! 위험해!","JPN":"おい！　危ないぞ！","ENG":"Hey! That's dangerous!","TWN":"喂！危險！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"그쪽은 우리가 나온 방향이라고!","JPN":"そっちは今出てきた方向だ！","ENG":"That's the way we came from!","TWN":"那邊是我們出來的方向！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…기다리게!","JPN":"……待つのだ！","ENG":"…Wait there!","TWN":"…等一下！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"혼자 어딜 급히 가는 거요…!","JPN":"一人でどこに行くつもりだ！","ENG":"Where do you think you're going alone…?!","TWN":"你要一個人去哪裡…！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화!!!","JPN":"レンカ！！","ENG":"Yeonhwa!!!","TWN":"蓮華！！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"呃？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그만 뛰어, 사부.","JPN":"師匠、ストップ！","ENG":"Enough running, Master.","TWN":"別再跑了，師父。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭘 쫓는진 몰라도 그 앞은 낭떠러지야.","JPN":"何を追いかけようとしてるのかは分からないけど、その先は崖っぷちだよ。","ENG":"I don't know who you're chasing, but it's nothing but a cliff past there.","TWN":"不管你在追什麼，前面只有懸崖。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_WIND"},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"아…! 보입니다!","JPN":"あ……！　見えます！","ENG":"Ah…! I see them!","TWN":"啊…！看到了！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"VIP와 카운터, 생존 확인! 전원 무사히 탈출했습니다!","JPN":"VIPとカウンターの生存を確認！　全員無事脱出しました！","ENG":"The VIP and the Counter are alive! They've all made it out safely!","TWN":"確認VIP和制裁者，平安！所有人都順利逃脫了！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"무사하셨군요! 다행입니다!","JPN":"無事でしたか！　よかったです！","ENG":"You're safe! Thank goodness!","TWN":"你沒事真是太好了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"와류흔 경계에서 기다리고 있었나? 다른 사태를 진압하러 갔을 줄 알았는데.","JPN":"渦流痕の境界で待っていたのか。他の事態の鎮圧に向かったと思ったが。","ENG":"You were waiting at the edge of the Vortex Scar? I thought you'd gone to handle another emergency.","TWN":"你們是在渦流痕邊界等嗎？我還以為你們去處理其他事態了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"약 8분 전, 먹구름이 걷히면서 상황이 어느 정도 진정됐습니다.","JPN":"約8分前に雲が消え、ある程度状況が安定しました。","ENG":"The dark clouds cleared up about eight minutes ago. The situation started to settle.","TWN":"大約八分鐘前，墨雲散去，情況穩定了下來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"저희는 경계에서 침식체가 튀어나올 걸 대비해 대기 중이었죠.","JPN":"私たちは侵食体が飛び出して来る可能性に備えて、待機していたのです。","ENG":"We stayed on standby in case more C.O.s popped out.","TWN":"我們在這裡待命，以防有侵蝕體跑出來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"괜찮아. 따라붙은 침식체는 없네.","JPN":"ついて来る侵食体などおらん。ご心配無用だ。","ENG":"It's fine. Nothing followed us out.","TWN":"沒事。沒有侵蝕體跟過來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 사람들을 병원으로 보내게. 일반인들은 침식에 면역이 없으니 후유증이 남을 수 있으니.","JPN":"この人たちを病院に送り届けたまえ。侵食に免疫を持たない一般人は後遺症が残る可能性がある。","ENG":"Get these people to a hospital. Civilians have no resistance to Corruption leading to lasting aftereffects.","TWN":"把這些人送去醫院。一般人對侵蝕沒有免疫力，可能會留下後遺症。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"그렇게 하겠습니다. 그럼…","JPN":"そうします。では……","ENG":"We'll make sure of it. Then…","TWN":"應該的。那麽…"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"잠깐만. 기다려 봐.","JPN":"待ってくれ。","ENG":"Wait. Hold on a moment.","TWN":"等一下。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"우선 고맙다는 말을 해야겠군.","JPN":"まずはお礼を言わねばならんな。","ENG":"First, I owe you my thanks.","TWN":"首先我要向你道謝。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"자네 도움이 없었으면 난 영영 저 검은 소용돌이 속에 갇혔겠지. 아니면 저기 쓰러진 괴물들 중 하나가 됐거나.","JPN":"君が助けに来てくれなければ、私はいつまでもあの黒い渦の中に閉じ込められていただろう。でなければ、あそこに倒れている化け物のうちの1体となっていたかもしれない。","ENG":"If not for you, I'd be stuck in that black vortex… Or worse, become one of those monsters lying over there.","TWN":"沒有你的幫助，我可能會永遠被困在那個黑色渦流痕裡。不然就是變成那些倒下的怪物之一。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그 말씀대로요. 와류흔은 침식의 강도가 가장 높은 지점이니.","JPN":"……その通りだ。渦流痕は侵食の強度が最も高い地点だからな。","ENG":"…You're not wrong. The Vortex Scar is where Corruption is most concentrated.","TWN":"…正如你所說。渦流痕是侵蝕強度最高的地點。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"저 산골에서 먹비를 수 년째 조사하는 유별난 카운터가 있다고 들은 적이 있지.","JPN":"あの山奥で数年前から墨雨を研究している変わったカウンターがいると聞いたことがある。","ENG":"I heard there was an eccentric Counter tucked away in the mountains who's been studying Ink Rain for years.","TWN":"我聽說過，在這深山裡，有一個古怪的制裁者，調查墨雨好幾年了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"날 구하러 온 이유가 관리국의 지시가 아니라면, 뭐지?","JPN":"管理局の指示ではないとするなら、何故私を助けに来たのだ？","ENG":"If it wasn’t the Administration’s orders that brought you here to save me… then what was?","TWN":"你來救我，如果不是管理局的指示，那是為了什麼？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"침식체로부터 도시를 구하는 건 관리국이 충분히 해낼 일이요.","JPN":"侵食体から都市を救うことは管理局でも十分できる。","ENG":"Protecting the city from C.O.s is the Administration's job.","TWN":"拯救城市免於侵蝕體，是管理局能辦到的事。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나, 와류흔에 갇힌 이를 구하는 것은 본인만이 할 수 있는 일이라 생각하였을 뿐.","JPN":"されど渦流痕に閉じ込められた者を助けることは、某にしかできぬことだと思ったまでだ。","ENG":"But rescuing someone trapped in a Vortex Scar is something I believed only I could do.","TWN":"但是，我認為只有我才能拯救被困在渦流痕裡的人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"하하하, 좋은 대답이구만.","JPN":"ははは、いい返事だ。","ENG":"Hahaha! That's a fine answer.","TWN":"哈哈，這回答真不錯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"나도 자네 나이 때 그런 마음가짐으로 살았지.","JPN":"私も君くらいの頃は、そんな心構えで生きていたものだ。","ENG":"I used to think that way too, back when I was your age.","TWN":"我像你這個年紀時，也有這種心態。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"이건 <color=#ffd34c>나 밖에 할 수 없는 일</color>이기 때문에 하는 거라고.","JPN":"これは<color=#ffd34c>自分にしかできないこと</color>だからやるのだと。","ENG":"That I was doing this because <color=#ffd34c>I was the only one who could</color>.","TWN":"這件事只有我能辦到，所以我才要去做。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"회장님. 전용기가 도착했습니다.","JPN":"会長、専用機が着きました。","ENG":"President, your private jet has arrived.","TWN":"會長，專機到了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"자네. 평소엔 무슨 일을 하고 있나?","JPN":"君、普段はどんな仕事をしている？","ENG":"What do you do normally, if I may ask?","TWN":"你，平常在做什麼工作？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"공방을 운영하고 있소.","JPN":"工房を経営している。","ENG":"I run a workshop.","TWN":"我在經營工作室。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쓸만한 도구 만드는 일을 겸하여, 과거로 가는 법도 연구하고 있지.","JPN":"使える道具を作るのも兼ねて、過去へ行ける方法を研究中だ。","ENG":"I make tools and research ways to travel back in time.","TWN":"兼職做些有用的工具，同時也在研究回到過去的方法。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"과거로 가는 법이라… 와류흔에 대한 소문이 사실이었나 보군.","JPN":"過去へ行ける方法か……渦流痕の噂は本当だったのだな。","ENG":"A way to travel back in time… So the rumors about the Vortex Scar were true.","TWN":"回到過去的方法…看來關於渦流痕的傳聞是真的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"하긴, 그런 험한 산골짜기에 연구소를 차릴 이유가 그리 많진 않겠지.","JPN":"確かに、あんな険しい山奥に研究所を設ける理由などそうないだろう。","ENG":"Not many other reasons to build a lab in a place like that, I suppose.","TWN":"說得也是，要在這種險峻的山區開設研究室，理由可不多。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"그럼 기회가 닿으면 또 만나지. 박사.","JPN":"では、機会があればまた会おう、博士。","ENG":"Then let's meet again if the opportunity arises, Doctor.","TWN":"那麽，有緣再見吧，博士。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"그 꿈. 포기하지 말고 계속 밀어붙이게.","JPN":"その夢、諦めずに突き進むといい。","ENG":"Don't give up on that dream. Keep pushing forward.","TWN":"那個夢想。不要放棄，繼續努力吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 아저씨… 어디서 본 적이 있는 얼굴인데.","JPN":"あのおじさん……どこかで見た気がするんだよね。","ENG":"That man… I swear I've seen his face somewhere.","TWN":"那位大叔…我好像在哪裡見過。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"기업, 알파트릭스로부터 송금…?","JPN":"企業、アルファトリックスからの振込……？","ENG":"Transfer received from Alphatrix…?","TWN":"阿爾法崔克斯入帳…？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐야 이거?! 대체 0이 몇 개야?!","JPN":"何これ！？　0がいくつついてるの！？","ENG":"What the?! How many zeroes is that?!","TWN":"這是什麼？！有幾個零啊？！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};